esqlQuery.esql:
// Alert when LDAP operations exceed a latency threshold.
// High latency impacts authentication, sudo resolution, and HBAC evaluation.
// Adjust the threshold (in seconds) in the final WHERE clause as needed.
FROM logs-freeipa.directory_access-*
| WHERE freeipa.directory.operation == "RESULT" AND freeipa.directory.elapsed_time IS NOT NULL
| STATS p95_latency = PERCENTILE(freeipa.directory.elapsed_time, 95), op_count = COUNT(*)
| WHERE op_count >= 10 AND p95_latency >= 5.0
